import { useState, useEffect, useMemo, useCallback } from "react";
import { useTranslation } from "react-i18next";
import { useQuery } from "@tanstack/react-query";
import { Check, ChevronsUpDown, MapPin, Search, X, Loader2 } from "lucide-react";
import { useIsMobile } from "@/hooks/use-mobile";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { cn } from "@/lib/utils";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import {
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
  DrawerFooter,
} from "@/components/ui/drawer";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";

interface Restaurant {
  id: string;
  name?: string;
  name_zh?: string;
  name_en?: string;
  name_pt?: string;
  address?: string;
  type?: string | string[];
  country?: string | null;
  city?: string | null;
}

interface MultiRestaurantSelectDrawerProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  value: string[];
  onSelect: (restaurantIds: string[]) => void;
  restaurants?: Restaurant[]; // kept for backward compat but ignored
  required?: boolean;
  maxDisplay?: number;
}

// Reverse geocode coords to country code
async function reverseGeocodeCountry(lat: number, lng: number): Promise<string | null> {
  try {
    const resp = await fetch(
      `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json&zoom=3&addressdetails=1`,
      { headers: { "Accept-Language": "en" } }
    );
    const data = await resp.json();
    return data?.address?.country || null;
  } catch {
    return null;
  }
}

const MultiRestaurantSelectDrawer = ({
  open,
  onOpenChange,
  value,
  onSelect,
  required = false,
  maxDisplay = 2,
}: MultiRestaurantSelectDrawerProps) => {
  const { t } = useTranslation();
  const { getLocalizedField } = useLocalizedContent();
  const isMobile = useIsMobile();
  const [search, setSearch] = useState("");
  const [debouncedSearch, setDebouncedSearch] = useState("");
  const [pendingValue, setPendingValue] = useState<string[]>(value);
  const [userCountry, setUserCountry] = useState<string | null>(null);
  const [locating, setLocating] = useState(false);
  const [drawerHeight, setDrawerHeight] = useState<string>('90vh');

  // Debounce search input
  useEffect(() => {
    const timer = setTimeout(() => setDebouncedSearch(search), 350);
    return () => clearTimeout(timer);
  }, [search]);

  // Get geolocation when drawer opens
  useEffect(() => {
    if (!open) return;
    if (userCountry) return; // already got it

    setLocating(true);
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const country = await reverseGeocodeCountry(pos.coords.latitude, pos.coords.longitude);
        setUserCountry(country);
        setLocating(false);
      },
      () => {
        setLocating(false);
      },
      { timeout: 5000 }
    );
  }, [open, userCountry]);

  // Monitor visualViewport for mobile keyboard
  useEffect(() => {
    if (!open || !isMobile) return;
    const viewport = window.visualViewport;
    if (!viewport) { setDrawerHeight('90vh'); return; }
    const updateHeight = () => {
      const h = viewport.height;
      setDrawerHeight(`${Math.min(h * 0.9, h - 40)}px`);
    };
    updateHeight();
    viewport.addEventListener('resize', updateHeight);
    return () => viewport.removeEventListener('resize', updateHeight);
  }, [open, isMobile]);

  // Search restaurants from DB (dynamic, max 50)
  const { data: searchedRestaurants, isLoading: searching } = useQuery({
    queryKey: ["multiSelectRestaurants", debouncedSearch, userCountry],
    queryFn: async () => {
      let query = supabase
        .from("restaurants")
        .select("id,name,name_en,name_pt,address,country,city")
        .eq("visible", true)
        .limit(50);

      if (debouncedSearch) {
        query = query.or(
          `name.ilike.%${debouncedSearch}%,name_en.ilike.%${debouncedSearch}%,name_pt.ilike.%${debouncedSearch}%,address.ilike.%${debouncedSearch}%`
        );
      }

      // Prioritize user's country
      if (userCountry) {
        query = query.order("country", { ascending: true }); // will be re-sorted below
      }

      query = query.order("name", { ascending: true });

      const { data, error } = await query;
      if (error) throw error;

      // Sort: user's country first
      if (userCountry && data) {
        const countryLower = userCountry.toLowerCase();
        return data.sort((a, b) => {
          const aMatch = a.country?.toLowerCase() === countryLower ? 0 : 1;
          const bMatch = b.country?.toLowerCase() === countryLower ? 0 : 1;
          return aMatch - bMatch;
        }) as Restaurant[];
      }

      return (data || []) as Restaurant[];
    },
    enabled: open,
    staleTime: 1000 * 30,
  });

  // Fetch selected restaurants' metadata (for display)
  const { data: selectedRestaurants } = useQuery({
    queryKey: ["selectedRestaurantsMeta", value],
    queryFn: async () => {
      if (value.length === 0) return [];
      const { data, error } = await supabase
        .from("restaurants")
        .select("id,name,name_en,name_pt,address,country,city")
        .in("id", value);
      if (error) throw error;
      return (data || []) as Restaurant[];
    },
    enabled: value.length > 0,
    staleTime: 1000 * 60 * 5,
  });

  // Merge: selected restaurants + searched results (deduplicated)
  const displayRestaurants = useMemo(() => {
    const selectedMap = new Map<string, Restaurant>();
    (selectedRestaurants || []).forEach(r => selectedMap.set(r.id, r));
    const searched = searchedRestaurants || [];
    searched.forEach(r => {
      if (!selectedMap.has(r.id)) selectedMap.set(r.id, r);
    });
    // Put selected first, then searched
    const selected = (selectedRestaurants || []).filter(r => pendingValue.includes(r.id));
    const rest = [...selectedMap.values()].filter(r => !pendingValue.includes(r.id));
    return [...selected, ...rest];
  }, [searchedRestaurants, selectedRestaurants, pendingValue]);

  // Reset pending value when drawer opens
  const handleOpenChange = useCallback((newOpen: boolean) => {
    if (newOpen) {
      setPendingValue(value);
      setSearch("");
      setDebouncedSearch("");
    }
    onOpenChange(newOpen);
  }, [value, onOpenChange]);

  const toggleRestaurant = (restaurantId: string) => {
    setPendingValue(prev =>
      prev.includes(restaurantId)
        ? prev.filter(id => id !== restaurantId)
        : [...prev, restaurantId]
    );
  };

  const handleConfirm = () => {
    onSelect(pendingValue);
    onOpenChange(false);
    setSearch("");
  };

  // Desktop: immediate toggle
  const handleDesktopToggle = (restaurantId: string) => {
    const newValue = value.includes(restaurantId)
      ? value.filter(id => id !== restaurantId)
      : [...value, restaurantId];
    onSelect(newValue);
  };

  // Display names for trigger
  const getSelectedNames = () => {
    return value
      .map(id => {
        const restaurant = selectedRestaurants?.find(r => r.id === id);
        return restaurant ? getLocalizedField(restaurant, "name") : null;
      })
      .filter(Boolean) as string[];
  };

  const selectedNames = getSelectedNames();

  const TriggerContent = () => {
    if (selectedNames.length === 0) {
      return (
        <span className="text-muted-foreground">
          {t("community.linkRestaurants", "关联餐厅")}
          {required && <span className="text-destructive ml-1">*</span>}
        </span>
      );
    }
    const displayNames = selectedNames.slice(0, maxDisplay);
    const remaining = selectedNames.length - maxDisplay;
    return (
      <span className="text-primary flex items-center gap-1 flex-wrap">
        {displayNames.map((name, i) => (
          <span key={i}>{name}{i < displayNames.length - 1 ? "、" : ""}</span>
        ))}
        {remaining > 0 && (
          <Badge variant="secondary" className="text-xs px-1.5 py-0">+{remaining}</Badge>
        )}
      </span>
    );
  };

  const triggerInner = (
    <>
      <TriggerContent />
      <ChevronsUpDown className="h-4 w-4 opacity-50 shrink-0" />
    </>
  );

  // Restaurant item
  const RestaurantItem = ({ restaurant, isSelected, onToggle }: {
    restaurant: Restaurant; isSelected: boolean; onToggle: () => void;
  }) => (
    <div
      className={cn(
        "flex items-start gap-3 py-3 px-3 rounded-lg cursor-pointer transition-colors",
        isSelected ? "bg-primary/10" : "hover:bg-muted"
      )}
      onClick={onToggle}
    >
      <div className={cn(
        "h-5 w-5 shrink-0 mt-0.5 rounded border flex items-center justify-center transition-colors",
        isSelected ? "bg-primary border-primary" : "border-muted-foreground/30"
      )}>
        {isSelected && <Check className="h-3 w-3 text-primary-foreground" />}
      </div>
      <div className="flex-1 min-w-0">
        <p className="font-medium truncate">{getLocalizedField(restaurant, "name")}</p>
        {restaurant.address && (
          <p className="text-sm text-muted-foreground truncate flex items-center gap-1 mt-0.5">
            <MapPin className="h-3 w-3 shrink-0" />
            {restaurant.address}
          </p>
        )}
        {restaurant.country && (
          <p className="text-xs text-muted-foreground/70 mt-0.5">
            {[restaurant.city, restaurant.country].filter(Boolean).join(", ")}
          </p>
        )}
      </div>
    </div>
  );

  // Search + list content (shared between mobile & desktop)
  const SearchAndList = ({ isSelectedFn, onToggleFn }: {
    isSelectedFn: (id: string) => boolean;
    onToggleFn: (id: string) => void;
  }) => (
    <>
      {/* Search */}
      <div className="px-4 pb-3 shrink-0">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder={t("community.searchRestaurant", "搜索餐厅...")}
            value={search}
            onChange={e => setSearch(e.target.value)}
            className="pl-9"
            autoFocus={!isMobile}
          />
        </div>
        {locating && (
          <p className="text-xs text-muted-foreground mt-1.5 flex items-center gap-1">
            <Loader2 className="h-3 w-3 animate-spin" />
            {t("community.locatingForBetterResults", "正在定位以优先显示附近餐厅...")}
          </p>
        )}
        {userCountry && !debouncedSearch && (
          <p className="text-xs text-muted-foreground mt-1.5">
            📍 {t("community.showingNearbyFirst", "优先显示 {{country}} 的餐厅", { country: userCountry })}
          </p>
        )}
      </div>

      {/* Selected badges */}
      {pendingValue.length > 0 && (
        <div className="px-4 pb-3 shrink-0">
          <div className="flex flex-wrap gap-1.5">
            {pendingValue.map(id => {
              const restaurant = displayRestaurants.find(r => r.id === id) || selectedRestaurants?.find(r => r.id === id);
              if (!restaurant) return null;
              return (
                <Badge key={id} variant="secondary" className="gap-1 pr-1">
                  <span className="truncate max-w-[120px]">{getLocalizedField(restaurant, "name")}</span>
                  <button
                    type="button"
                    className="hover:bg-muted-foreground/20 rounded-full p-0.5"
                    onClick={e => { e.stopPropagation(); setPendingValue(prev => prev.filter(i => i !== id)); }}
                  >
                    <X className="h-3 w-3" />
                  </button>
                </Badge>
              );
            })}
          </div>
        </div>
      )}

      {/* Restaurant list */}
      <div className="flex-1 overflow-y-auto px-4 min-h-0">
        {searching && (
          <div className="py-6 flex justify-center">
            <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
          </div>
        )}
        {!searching && (
          <div className="space-y-1 pb-4">
            {displayRestaurants.map(restaurant => (
              <RestaurantItem
                key={restaurant.id}
                restaurant={restaurant}
                isSelected={isSelectedFn(restaurant.id)}
                onToggle={() => onToggleFn(restaurant.id)}
              />
            ))}
            {displayRestaurants.length === 0 && debouncedSearch && (
              <div className="py-6 text-center text-muted-foreground">
                {t("community.noRestaurantFound", "未找到匹配的餐厅")}
              </div>
            )}
            {displayRestaurants.length === 0 && !debouncedSearch && !searching && (
              <div className="py-6 text-center text-muted-foreground text-sm">
                {t("community.typeToSearchRestaurant", "输入关键词搜索餐厅")}
              </div>
            )}
          </div>
        )}
      </div>
    </>
  );

  // Mobile: Drawer
  if (isMobile) {
    return (
      <>
        <button
          type="button"
          className="flex items-center gap-1 text-sm hover:text-primary transition-colors text-left"
          onClick={() => handleOpenChange(true)}
        >
          {triggerInner}
        </button>
        <Drawer open={open} onOpenChange={handleOpenChange}>
          <DrawerContent
            className="flex flex-col"
            style={{ height: drawerHeight, maxHeight: drawerHeight, transition: 'height 0.15s ease-out' }}
          >
            <DrawerHeader className="pb-2 shrink-0">
              <DrawerTitle>
                {t("community.selectRestaurants", "选择餐厅")}
                {pendingValue.length > 0 && <Badge variant="secondary" className="ml-2">{pendingValue.length}</Badge>}
              </DrawerTitle>
            </DrawerHeader>
            <SearchAndList
              isSelectedFn={id => pendingValue.includes(id)}
              onToggleFn={id => toggleRestaurant(id)}
            />
            <DrawerFooter className="pt-2">
              <div className="flex gap-3">
                <Button variant="outline" className="flex-1" onClick={() => handleOpenChange(false)}>
                  {t("common.cancel", "取消")}
                </Button>
                <Button className="flex-1" onClick={handleConfirm}>
                  {t("community.confirmSelection", "确认选择")}
                  {pendingValue.length > 0 && ` (${pendingValue.length})`}
                </Button>
              </div>
            </DrawerFooter>
          </DrawerContent>
        </Drawer>
      </>
    );
  }

  // Desktop: Dialog (larger than popover)
  return (
    <>
      <button
        type="button"
        className="flex items-center gap-1 text-sm hover:text-primary transition-colors text-left"
        onClick={() => handleOpenChange(true)}
      >
        {triggerInner}
      </button>
      <Dialog open={open} onOpenChange={handleOpenChange}>
        <DialogContent className="max-w-lg max-h-[70vh] flex flex-col p-0 gap-0">
          <DialogHeader className="p-4 pb-2 shrink-0">
            <DialogTitle>
              {t("community.selectRestaurants", "选择餐厅")}
              {value.length > 0 && <Badge variant="secondary" className="ml-2">{value.length}</Badge>}
            </DialogTitle>
          </DialogHeader>
          <SearchAndList
            isSelectedFn={id => value.includes(id)}
            onToggleFn={id => handleDesktopToggle(id)}
          />
          <DialogFooter className="p-4 pt-2 shrink-0">
            <Button variant="outline" onClick={() => handleOpenChange(false)}>
              {t("common.close", "关闭")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
};

export default MultiRestaurantSelectDrawer;
